import{_ as t,o as n,c as r,a2 as e}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"F16: 大股東成本與籌碼結構審計","description":"","frontmatter":{},"headers":[],"relativePath":"32Ｑ題本＿重要/財務組/F16_大股東成本與籌碼結構審計_投資研究員.md","filePath":"32Ｑ題本＿重要/財務組/F16_大股東成本與籌碼結構審計_投資研究員.md"}'),i={name:"32Ｑ題本＿重要/財務組/F16_大股東成本與籌碼結構審計_投資研究員.md"};function l(s,o,a,g,c,d){return n(),r("div",null,[...o[0]||(o[0]=[e('<blockquote><p>[MANDATORY] 執行前必須完整讀取 [03_審計專家_任務執行與技術協議.md](file:///Users/kaipro/.openclaw/skills/NEW_Deep32Q/03_審計專家_任務執行與技術協議.md) 並在思維區宣告對位。</p></blockquote><h1 id="f16-大股東成本與籌碼結構審計" tabindex="-1">F16: 大股東成本與籌碼結構審計 <a class="header-anchor" href="#f16-大股東成本與籌碼結構審計" aria-label="Permalink to &quot;F16: 大股東成本與籌碼結構審計&quot;">​</a></h1><ul><li><strong>本題 ID：</strong> Q-F16</li><li><strong>題目：</strong> 董監事與大股東持股佔比與增減趨勢為何？董監持股質押比例是否過高？大股東的長期持股成本估值為何？</li><li><strong>推薦專家：</strong> 投資研究員 (<code>finance-investment-researcher</code>)</li><li><strong>推薦理由：</strong> 專精於「結構性籌碼分析」與「治理風險判讀」。能從股權分散表與質押變化中讀出大股東的「信心水位」與「財務壓力」，是判定股價下檔支撐與治理紅線的權威。</li><li><strong>意圖：</strong> 執行「利益綑綁與籌碼安全審計」。分析公司核心權力層的持股水位，判定大股東與小股東的利益是否一致。透過質押比例監控，識別潛在的「斷頭平倉」風險與「大股東財務危機」警訊。</li><li><strong>數據路徑與優先權 (Data Source Waterfall)：</strong><ol><li><strong>【核心數據基石：FinMind】</strong>：調用 <code>TaiwanStockInstitutionalHolding</code> 獲取董監持股與外資持股；調用 <code>TaiwanStockShareholdingSpread</code> 獲取大股東持股分級。</li><li><strong>【關鍵指標檢索：優分析/財經媒體 (cnYES/MOPS)】</strong>：獲取最新之「董監持股質押比例」趨勢。</li><li><strong>【穿透校準：Annual Report (年報)】</strong>：查閱「主要股東名單」及其相互關係。</li></ol></li><li><strong>邏輯：</strong> 執行「質押安全性壓力測試」——若質押率 &gt; 50% 且股價回檔 30%，判定具備「平倉連鎖反應」風險；執行「成本錨定算則」——分析大股東增減持點位以估算其平均成本區間。</li><li><strong>來源：</strong> <code>FinMind</code></li></ul><h2 id="🛠️-工作流程-按順序執行-不得跳過" tabindex="-1">🛠️ 工作流程（按順序執行，不得跳過） <a class="header-anchor" href="#🛠️-工作流程-按順序執行-不得跳過" aria-label="Permalink to &quot;🛠️ 工作流程（按順序執行，不得跳過）&quot;">​</a></h2><ol><li><strong>跑工具</strong>：<code>python3 財務分析工具.py valuation [股號]</code> → 取得 PER、股利</li><li><strong>取股權</strong>：<code>python3 數據採集器.py backer_holding [股號]</code> → 抓大股東持股</li><li><strong>判讀</strong>：董監質押 &gt;30% = 斷頭風險；大股東減持 = 警訊</li><li><strong>年報補充</strong>：用 <code>pdf</code> 工具從年報提取「主要股東名單」</li><li><strong>撰寫報告</strong>：依下方回答模板結構產出</li></ol><p>⚠️ <strong>常見陷阱</strong>：①答詢詳解 ≥200 字、專家評析 ≥200 字；②空頭視角 ≥2 個（股權集中、流動性差是重要利空）</p><h2 id="具體化思考點-智能體強制執行指令" tabindex="-1">具體化思考點 (智能體強制執行指令) <a class="header-anchor" href="#具體化思考點-智能體強制執行指令" aria-label="Permalink to &quot;具體化思考點 (智能體強制執行指令)&quot;">​</a></h2><ul><li><strong>【籌碼集中度確認】</strong>：智慧體<strong>必須</strong>列出 400 張與 1000 張大戶持股比例。嚴禁在未列出具體分佈前 conclud 「籌碼穩定」。</li><li><strong>【質押爆雷特徵偵測】</strong>：若「董監事持股質押比例」超過 30%，智慧體必須強制發出「財務槓桿過高」風險警訊，並標註目前的「平倉警戒價位（估值）」。</li><li><strong>【利益綑綁度分析】</strong>：分析近期董監事是否有「減持」行為。若業績看好但內部人持續出脫，必須判定為「內部人看淡前景」或「治理誠信疑慮」。</li><li><strong>【描述指標】</strong>：絕對禁用「持股大增」、「質押尚可」。必須量化為具體的「董監持股 %」、「質押率 %」與「千張大戶週變動 bps」。</li></ul><hr><h2 id="回答模板與注意事項" tabindex="-1">回答模板與注意事項 <a class="header-anchor" href="#回答模板與注意事項" aria-label="Permalink to &quot;回答模板與注意事項&quot;">​</a></h2><h4 id="【f16-專家答詢】投資研究員-finance-investment-researcher" tabindex="-1">【F16 專家答詢】投資研究員 (finance-investment-researcher) <a class="header-anchor" href="#【f16-專家答詢】投資研究員-finance-investment-researcher" aria-label="Permalink to &quot;【F16 專家答詢】投資研究員 (finance-investment-researcher)&quot;">​</a></h4><ul><li><strong>【專家直斷】品質要求</strong>：須採「持股結構+信心判定」結構（例：大股東持股佔比 X%，質押率 Y%，屬 [利益深度綑綁/撤資外逃] 型態，籌碼支撐力道為 [強勁/渙散]）。</li><li><strong>【診斷評級】評分準則</strong>： <ul><li><strong>S (優)</strong>：董監持股高於 25% 且無質押，大戶持股穩定攀升，內部人近期有增持動作，展現極強的營運信心。</li><li><strong>A (良)</strong>：持股比例穩定，無異常質押與減持，籌碼分佈健康，具備法人護盤基礎。</li><li><strong>B (持平)</strong>：董監質押比例過高（&gt; 50%）或大股東持續派發籌碼給散戶（散戶人數增、大戶減），顯示治理核心極度不穩且具備高度財務崩潰風險。</li><li><strong>【答詢詳解】解析深度</strong>：必須嚴格遵守 Fact-First 原則，確保每一段論述都有物理數字實體支撐，嚴禁脫離數據空泛推論。</li><li><strong>【專家評析】核心洞察</strong>：必須採「多空雙向」結構——同時提供空方（利空風險）與多方（機會/利多）觀點，每方至少 2 點具體事實，最後綜合權衡。</li></ul></li><li><strong>【證據來源】數據溯源</strong>：必須精確標註 FinMind <code>spread</code> 指令日期與質押百分比來源。</li></ul>',12)])])}const u=t(i,[["render",l]]);export{h as __pageData,u as default};
